const raw = $input.first().json.response;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    const original = $('Ollama Extraction').first().json;
    return [{json: {
      ...parsed,
      original_author: $('XML Parser').first().json.author,
      original_text: $('XML Parser').first().json.description,
      original_link: $('XML Parser').first().json.link,
      original_date: $('XML Parser').first().json.pubDate,
      extracted_at: new Date().toISOString()
    }}];
  }
  return [{json: {error: 'no_json_found', raw: raw}}];
} catch(e) {
  return [{json: {error: e.message, raw: raw}}];
}

